    Result_header = $fopen("../../../../../source_file/simulation/output/BFPQ_output_header.txt");
             
    for(i=0; i <10000000; i= i +1) begin 
        if(fOutValid)  begin  
            $fdisplay(Result_I1,"%0d ", (SignI1&((1<<8)-1))<<(wordlength-1)|MantissaI1);
            $fdisplay(Result_I2,"%0d ", (SignI2&((1<<8)-1))<<(wordlength-1)|MantissaI2);
            $fdisplay(Result_I3,"%0d ", (SignI3&((1<<8)-1))<<(wordlength-1)|MantissaI3);
            $fdisplay(Result_I4,"%0d ", (SignI4&((1<<8)-1))<<(wordlength-1)|MantissaI4);
            $fdisplay(Result_Q1,"%0d ", (SignQ1&((1<<8)-1))<<(wordlength-1)|MantissaQ1);
            $fdisplay(Result_Q2,"%0d ", (SignQ2&((1<<8)-1))<<(wordlength-1)|MantissaQ2);
