            $fdisplay(Result_Q4,"%0d ", (SignQ4&((1<<8)-1))<<(wordlength-1)|MantissaQ4);
            if(fBlockEnd==1'b1) begin
                $fdisplay(Result_header,"%d ", {Ce,Cw});
            end
        end
        #(CLK_CYCLE);
    end
    $fclose(Result_I1);
    $fclose(Result_I2);
    $fclose(Result_I3);
    $fclose(Result_I4);
